// We added the word 'data'
data class Player(val name: String, val score: Int)

fun main() {
    val p1 = Player("Bob", 500)
    val p2 = Player("Bob", 500)

    // Beautiful print formatting! (Usually prints ugly memory addresses)
    println(p1) // Prints: Player(name=Bob, score=500)

    // Accurately compares the internal data! (Usually fails)
    println(p1 == p2) // Prints: true
}
